mapper.select:
select sum(rel.count) as num from
( select count(*) count from admin_sm_user u where u.org_id = #{orgId, jdbcType=VARCHAR}
  union all
  select count(*) count from admin_sm_role r where r.org_id = #{orgId, jdbcType=VARCHAR}
  union all
  select count(*) count from admin_sm_duty d where d.org_id = #{orgId, jdbcType=VARCHAR}
  union all
  select count(*) count from admin_sm_dpt t where t.org_id = #{orgId, jdbcType=VARCHAR}) rel

SELECT T0.ORG_CODE, T0.UP_ORG_ID,T0.ORG_NAME, T0.ORG_LEVEL ,T0.ORG_ID
FROM admin_sm_org T0
${ew.customSqlSegment}
